tools.writeFile:
Writes content to a file in the workspace. First line of your argument must be the file path, remaining lines are the file content. Example:
src/utils.mjs
export function foo() { return 42; }

workspace.src/deepGet.mjs:
export function deepGet(obj, path) {
  const keys = path.split('.');
  let current = obj;
  for (const key of keys) {
    current = current[key];
  }
  return current;
}

workspace.tests/deepGet.test.mjs:
import { deepGet } from '../src/deepGet.mjs';

const assert = (c, m) => { if (!c) throw new Error(m); };

// Test 1: valid nested path
const r1 = deepGet({ a: { b: { c: 42 } } }, 'a.b.c');
assert(r1 === 42, 'deepGet({a:{b:{c:42}}}, "a.b.c") should be 42 but got ' + r1);

// Test 2: missing path returns undefined
const r2 = deepGet({ a: { b: 1 } }, 'a.c.d');
assert(r2 === undefined, 'deepGet({a:{b:1}}, "a.c.d") should be undefined but got ' + r2);

// Test 3: single-level path
const r3 = deepGet({ x: 'hello' }, 'x');
assert(r3 === 'hello', 'deepGet({x:"hello"}, "x") should be "hello" but got ' + r3);

// Test 4: null object returns undefined
const r4 = deepGet(null, 'a.b');
assert(r4 === undefined, 'deepGet(null, "a.b") should be undefined but got ' + r4);

// Test 5: undefined intermediate returns undefined
const r5 = deepGet({ a: undefined }, 'a.b.c');
assert(r5 === undefined, 'deepGet({a:undefined}, "a.b.c") should be undefined but got ' + r5);

console.log('ALL TESTS PASSED');
